// Données du glossaire TSSR (porté depuis la page HTML autonome, RAID restauré).
export interface GlossaryTerm { acronym: string; name: string; category: string; definition: string; tags: string[]; aliases?: string[]; links?: Array<{ label: string; href: string }>; }

/** Ancre stable d'un terme (pour le partage de lien et le deep-linking). */
export function glossarySlug(acronym: string): string {
  return acronym.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '').replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
}

export const GLOSSARY_CATEGORIES: Array<{ key: string; label: string }> = [
  { key: 'réseau', label: '🌐 Réseau & Infrastructure' },
  { key: 'sécurité', label: '🔒 Sécurité & Cybersécurité' },
  { key: 'système', label: '🖥️ Systèmes & Administration' },
  { key: 'protocole', label: '📡 Protocoles' },
  { key: 'virtualisation', label: '⚙️ Virtualisation' },
  { key: 'stockage', label: '💾 Stockage' },
  { key: 'hardware', label: '🔧 Hardware & Équipements' },
  { key: 'expression', label: '💬 Expressions & Concepts' },
];

export const GLOSSARY: GlossaryTerm[] = [
  // RÉSEAU
  { acronym: "OSI", name: "Open Systems Interconnection", category: "réseau", definition: "Modèle en <strong>7 couches</strong> standardisant les communications réseau. Couches : <strong>1-Physique</strong>, <strong>2-Liaison</strong>, <strong>3-Réseau</strong>, <strong>4-Transport</strong>, <strong>5-Session</strong>, <strong>6-Présentation</strong>, <strong>7-Application</strong>. Moyen mnémotechnique : <em>Please Do Not Throw Sausage Pizza Away</em> (de bas en haut).", tags: ["réseau"] },
  { acronym: "TCP/IP", name: "Transmission Control Protocol / Internet Protocol", category: "réseau", definition: "Suite de protocoles fondamentaux d'Internet. <strong>TCP</strong> garantit la livraison ordonnée des données (connexion orientée). <strong>IP</strong> assure l'adressage et le routage des paquets. Modèle en 4 couches : Accès réseau, Internet, Transport, Application.", tags: ["réseau", "protocole"] },
  { acronym: "IP", name: "Internet Protocol", category: "réseau", definition: "Protocole d'adressage et de routage. <strong>IPv4</strong> : adresse 32 bits (ex: <code>192.168.1.1</code>). <strong>IPv6</strong> : adresse 128 bits (ex: <code>2001:db8::1</code>). Chaque machine sur un réseau doit avoir une IP unique.", tags: ["réseau"] },
  { acronym: "CIDR", name: "Classless Inter-Domain Routing", category: "réseau", definition: "Notation pour exprimer un sous-réseau : <code>192.168.1.0/24</code>. Le <strong>/24</strong> signifie 24 bits de masque → 256 adresses (254 utilisables). Remplace la notation ancienne par classes (A, B, C).", tags: ["réseau"] },
  { acronym: "IPv4 / IPv6", name: "Internet Protocol version 4 / version 6", category: "réseau", definition: "Les deux versions de l'adressage IP. <strong>IPv4</strong> : adresse sur <strong>32 bits</strong>, écrite en 4 octets décimaux (ex: <code>192.168.1.10</code>), soit ~4 milliards d'adresses (presque épuisées). <strong>IPv6</strong> : adresse sur <strong>128 bits</strong>, écrite en hexadécimal (ex: <code>2001:db8::1</code>), offrant un nombre colossal d'adresses. Les deux coexistent aujourd'hui.", tags: ["réseau"] },
  { acronym: "MSR", name: "Masque de Sous-Réseau", category: "réseau", definition: "Le masque qui sépare, dans une adresse IP, la <strong>partie réseau</strong> de la <strong>partie machine</strong>. Ex: <code>255.255.255.0</code> (équivaut à <code>/24</code> en CIDR). En binaire, les bits à <strong>1</strong> = réseau, les bits à <strong>0</strong> = machine.", tags: ["réseau"] },
  { acronym: "idSR / NetID", name: "Identifiant de Sous-Réseau / Network ID", category: "réseau", definition: "L'<strong>adresse réseau</strong> : la <strong>première</strong> adresse d'un sous-réseau, qui identifie le réseau lui-même et n'est <strong>pas attribuable</strong> à une machine. Ex: pour <code>192.168.10.42/26</code>, l'idSR est <code>192.168.10.0</code>.", tags: ["réseau"] },
  { acronym: "Broadcast", name: "Adresse de diffusion", category: "réseau", definition: "La <strong>dernière</strong> adresse d'un sous-réseau : un message qui lui est envoyé est reçu par <strong>toutes les machines</strong> du réseau. Non attribuable à une machine. Ex: pour <code>192.168.10.0/26</code>, le broadcast est <code>192.168.10.63</code> (= idSR + nombre magique − 1).", tags: ["réseau"] },
  { acronym: "VLAN", name: "Virtual Local Area Network", category: "réseau", definition: "Segmentation logique d'un réseau physique. Permet d'isoler des groupes de machines sur le même switch physique. Chaque VLAN = réseau séparé. Les liaisons <strong>trunk</strong> transportent plusieurs VLANs entre switches.", tags: ["réseau"] },
  { acronym: "NAT", name: "Network Address Translation", category: "réseau", definition: "Traduction d'adresses réseau. Permet à plusieurs machines d'un réseau privé de partager une seule IP publique. Le routeur maintient une <strong>table de correspondance</strong> ports/IP. <strong>PAT</strong> (Port Address Translation) = variante la plus courante.", tags: ["réseau", "protocole"] },
  { acronym: "DHCP", name: "Dynamic Host Configuration Protocol", category: "réseau", definition: "Protocole d'attribution automatique d'adresses IP. Processus <strong>DORA</strong> : Discover → Offer → Request → Acknowledge. Port <code>67</code> (serveur) / <code>68</code> (client). Peut aussi distribuer masque, passerelle, DNS.", tags: ["réseau", "protocole"] },
  { acronym: "DNS", name: "Domain Name System", category: "réseau", definition: "Annuaire Internet : traduit un nom de domaine (<code>google.com</code>) en adresse IP. Port <code>53</code> (UDP/TCP). Types d'enregistrements : <strong>A</strong> (IPv4), <strong>AAAA</strong> (IPv6), <strong>MX</strong> (mail), <strong>CNAME</strong> (alias), <strong>PTR</strong> (reverse DNS).", tags: ["réseau", "protocole"] },
  { acronym: "ARP", name: "Address Resolution Protocol", category: "réseau", definition: "Résout une adresse IP en adresse MAC sur un réseau local. Fonctionne par <strong>broadcast</strong> : 'Qui a l'IP 192.168.1.1 ?'. La machine répond avec son adresse MAC. Résultat stocké dans le <strong>cache ARP</strong>.", tags: ["réseau", "protocole"] },
  { acronym: "MAC", name: "Media Access Control", category: "réseau", definition: "Adresse physique unique d'une carte réseau. Format : <code>XX:XX:XX:XX:XX:XX</code> en hexadécimal. Les 3 premiers octets identifient le <strong>fabricant</strong> (OUI). Fonctionne au niveau de la couche 2 (Liaison).", tags: ["réseau"] },
  { acronym: "LAN", name: "Local Area Network", category: "réseau", definition: "Réseau local limité à une zone géographique (bureau, bâtiment). S'oppose au <strong>WAN</strong> (réseau étendu, ex: Internet). Un <strong>MAN</strong> (Metropolitan Area Network) couvre une ville.", tags: ["réseau"] },
  { acronym: "WAN", name: "Wide Area Network", category: "réseau", definition: "Réseau étendu couvrant de grandes distances (villes, pays). Internet est le plus grand WAN. Utilise des liaisons louées, fibre optique longue distance, ou liaisons satellitaires.", tags: ["réseau"] },
  { acronym: "QoS", name: "Quality of Service", category: "réseau", definition: "Mécanisme de priorisation du trafic réseau. Permet de garantir la bande passante pour des services critiques (VoIP, visioconférence). Standard <strong>802.1p</strong> pour la QoS au niveau 2 (VLAN).", tags: ["réseau"] },
  { acronym: "STP", name: "Spanning Tree Protocol", category: "réseau", definition: "Protocole empêchant les boucles réseau dans les infrastructures switchées. Désactive automatiquement les liens redondants tout en gardant la redondance disponible en cas de panne. <strong>RSTP</strong> = version rapide.", tags: ["réseau", "protocole"] },
  { acronym: "OSPF", name: "Open Shortest Path First", category: "réseau", definition: "Protocole de routage dynamique à état de liens. Chaque routeur construit une carte complète du réseau et calcule le chemin le plus court (algorithme <strong>Dijkstra</strong>). Utilisé dans les grands réseaux d'entreprise.", tags: ["réseau", "protocole"] },
  { acronym: "BGP", name: "Border Gateway Protocol", category: "réseau", definition: "Protocole de routage inter-AS (entre opérateurs Internet). C'est le protocole qui 'fait fonctionner Internet'. Gère des centaines de milliers de routes. Très utilisé par les FAI et grandes entreprises.", tags: ["réseau", "protocole"] },

  // SÉCURITÉ
  { acronym: "VPN", name: "Virtual Private Network", category: "sécurité", definition: "Tunnel chiffré entre deux points sur Internet. Crée un réseau privé virtuel au-dessus d'un réseau public. Protocoles : <strong>IPsec</strong>, <strong>OpenVPN</strong>, <strong>WireGuard</strong>. Types : <strong>site-à-site</strong> (liaison entre deux réseaux) ou <strong>client-to-site</strong> (accès distant).", tags: ["sécurité", "réseau"] },
  { acronym: "DMZ", name: "DeMilitarized Zone", category: "sécurité", definition: "Zone réseau intermédiaire entre Internet et le réseau interne. Héberge les serveurs accessibles depuis l'extérieur (web, mail). Isolée du LAN par un firewall. Si un serveur DMZ est compromis, le LAN reste protégé.", tags: ["sécurité", "réseau"] },
  { acronym: "IDS", name: "Intrusion Detection System", category: "sécurité", definition: "Système de détection d'intrusions. Analyse le trafic réseau et les logs en mode <strong>passif</strong> — génère des alertes mais n'intervient pas. S'oppose à l'<strong>IPS</strong> (Intrusion Prevention System) qui bloque activement.", tags: ["sécurité"] },
  { acronym: "IPS", name: "Intrusion Prevention System", category: "sécurité", definition: "Système de prévention d'intrusions. Comme l'IDS mais en mode <strong>actif</strong> : bloque automatiquement le trafic suspect. Positionné en ligne dans le flux réseau. Risque de faux positifs pouvant bloquer du trafic légitime.", tags: ["sécurité"] },
  { acronym: "SIEM", name: "Security Information and Event Management", category: "sécurité", definition: "Plateforme centralisant la collecte, corrélation et analyse des logs de sécurité. Permet de détecter des incidents en croisant des événements de sources multiples. Outils : <strong>Splunk</strong>, <strong>Elastic SIEM</strong>, <strong>Wazuh</strong>.", tags: ["sécurité"] },
  { acronym: "SOC", name: "Security Operations Center", category: "sécurité", definition: "Centre opérationnel de cybersécurité. Équipe dédiée à la surveillance, détection et réponse aux incidents de sécurité 24h/24. Utilise des outils SIEM, SOAR, threat intelligence.", tags: ["sécurité"] },
  { acronym: "PKI", name: "Public Key Infrastructure", category: "sécurité", definition: "Infrastructure à clés publiques. Système de gestion des certificats numériques. Comprend une <strong>AC</strong> (Autorité de Certification) qui signe les certificats. Base du HTTPS, VPN, signature numérique.", tags: ["sécurité"] },
  { acronym: "ACL", name: "Access Control List", category: "sécurité", definition: "Liste de règles de contrôle d'accès. Sur un routeur/switch : filtre le trafic selon IP source/destination, protocole, port. Sur un système de fichiers : définit qui peut lire/écrire/exécuter. Mécanisme fondamental de sécurité réseau.", tags: ["sécurité", "réseau"] },
  { acronym: "MFA", name: "Multi-Factor Authentication", category: "sécurité", definition: "Authentification multifacteur. Combine plusieurs facteurs : <strong>quelque chose que vous savez</strong> (mot de passe), <strong>que vous possédez</strong> (téléphone/token), <strong>que vous êtes</strong> (biométrie). Réduit drastiquement le risque de compromission de compte.", tags: ["sécurité"] },
  { acronym: "RBAC", name: "Role-Based Access Control", category: "sécurité", definition: "Contrôle d'accès basé sur les rôles. Les permissions sont attribuées à des rôles (ex: admin, user, auditeur), et les utilisateurs sont assignés à des rôles. Plus facile à gérer que d'attribuer des permissions individuellement.", tags: ["sécurité", "système"] },
  { acronym: "ANSSI", name: "Agence Nationale de la Sécurité des Systèmes d'Information", category: "sécurité", definition: "Autorité nationale française en cybersécurité. Publie des guides, référentiels et recommandations. Certifie des produits et des prestataires de sécurité (<strong>PASSI</strong>). Rattachée au SGDSN.", tags: ["sécurité"] },
  { acronym: "RGPD", name: "Règlement Général sur la Protection des Données", category: "sécurité", definition: "Règlement européen sur la protection des données personnelles (2018). Impose le <strong>Privacy by Design</strong>, la minimisation des données, le droit à l'oubli. Amendes jusqu'à 4% du CA mondial. DPO obligatoire pour certaines structures.", tags: ["sécurité"] },
  { acronym: "PCA", name: "Plan de Continuité d'Activité", category: "sécurité", definition: "Document définissant comment maintenir l'activité en cas de sinistre. Définit le <strong>RTO</strong> (durée max d'interruption tolérée) et le <strong>RPO</strong> (perte de données maximale acceptable). Complémentaire au <strong>PRA</strong> (Plan de Reprise d'Activité).", tags: ["sécurité"] },

  // SYSTÈME
  { acronym: "AD", name: "Active Directory", category: "système", definition: "Annuaire centralisé Microsoft pour gérer utilisateurs, groupes, machines et politiques. Basé sur <strong>LDAP</strong> et <strong>Kerberos</strong>. Concept clé : le <strong>domaine</strong> (ex: <code>entreprise.local</code>). Administré via <strong>ADUC</strong> ou PowerShell.", tags: ["système"] },
  { acronym: "GPO", name: "Group Policy Object", category: "système", definition: "Objet de stratégie de groupe dans Active Directory. Permet de déployer des configurations sur des machines/utilisateurs du domaine : fond d'écran, restrictions, logiciels, paramètres de sécurité. Appliquées dans l'ordre : <strong>LSDOU</strong> (Local, Site, Domaine, OU).", tags: ["système"] },
  { acronym: "LDAP", name: "Lightweight Directory Access Protocol", category: "système", definition: "Protocole d'accès aux annuaires. Utilisé par Active Directory, OpenLDAP. Port <code>389</code> (non chiffré) ou <code>636</code> (LDAPS). Permet de rechercher, ajouter, modifier des entrées dans un annuaire.", tags: ["système", "protocole"] },
  { acronym: "OU", name: "Organizational Unit", category: "système", definition: "Unité organisationnelle dans Active Directory. Permet de structurer l'annuaire (ex: par service, site géographique). On y applique des <strong>GPO</strong>. Contient des utilisateurs, groupes, machines, ou d'autres OU.", tags: ["système"] },
  { acronym: "DC", name: "Domain Controller", category: "système", definition: "Contrôleur de domaine Active Directory. Serveur central qui authentifie les utilisateurs (<strong>Kerberos</strong>), stocke l'annuaire et applique les GPO. Minimum 2 DC recommandés pour la redondance. Le premier DC = <strong>PDC Emulator</strong>.", tags: ["système"] },
  { acronym: "FSMO", name: "Flexible Single Master Operations", category: "système", definition: "Les <strong>5 rôles à maître unique</strong> d'Active Directory, chacun tenu par <strong>un seul</strong> contrôleur de domaine, pour centraliser des opérations critiques et éviter les conflits. <strong>2 au niveau forêt</strong> : <strong>Maître de schéma</strong> (modifications du schéma AD) et <strong>Maître d'attribution de noms</strong> (ajout/suppression de domaines). <strong>3 au niveau domaine</strong> : <strong>Maître RID</strong> (attribue les identifiants uniques / SID), <strong>Émulateur PDC</strong> (authentification, mots de passe, synchro horaire) et <strong>Maître d'infrastructure</strong> (références entre objets de domaines différents). Rôles <strong>transférables</strong> en cas de panne ou de maintenance.", tags: ["système"] },
  { acronym: "SYSVOL", name: "System Volume", category: "système", definition: "Dossier <strong>partagé</strong> présent sur <strong>chaque contrôleur de domaine</strong>. Il stocke les données qui doivent être <strong>répliquées entre les DC</strong> ou accessibles par les clients : les <strong>stratégies de groupe (GPO)</strong> et les <strong>scripts de connexion</strong>. Répliqué automatiquement entre tous les DC, accessible par le réseau, il est <strong>indispensable au fonctionnement des GPO</strong>. Chemin : <code>C:\\Windows\\SYSVOL</code>.", tags: ["système"] },
  { acronym: "Approbation", name: "Relation d'approbation (Trust)", category: "système", definition: "Lien de <strong>confiance</strong> entre domaines ou forêts pour autoriser l'accès aux ressources de l'un depuis l'autre. Sens : <strong>unidirectionnelle</strong> (A→B) ou <strong>bidirectionnelle</strong> (A↔B). Portée : <strong>transitive</strong> (si A approuve B et B approuve C, alors A approuve C) ou non. Les approbations <strong>parent/enfant</strong> (même forêt, ex. <code>toulouse.adrar.local</code> sous <code>adrar.local</code>) sont automatiques, transitives et bidirectionnelles ; les approbations <strong>externes</strong> (forêts différentes) sont unidirectionnelles et non transitives.", tags: ["système", "sécurité"] },
  { acronym: "Délégation", name: "Délégation de contrôle", category: "système", definition: "Confier certaines <strong>tâches d'administration</strong> (réinitialiser un mot de passe, créer des utilisateurs, joindre un ordinateur au domaine…) à des utilisateurs ou <strong>groupes</strong>, sans leur donner tous les droits d'administrateur. Applique le <strong>principe du moindre privilège</strong> et se configure généralement au niveau d'une <strong>UO</strong> (ADUC → clic droit sur l'UO → « Délégation de contrôle »).", tags: ["système", "sécurité"] },
  { acronym: "GC", name: "Catalogue global (Global Catalog)", category: "système", definition: "Rôle d'un contrôleur de domaine qui héberge une <strong>copie partielle de TOUS les objets de la forêt</strong> (uniquement les attributs les plus utiles). Il accélère la <strong>recherche d'objets dans toute la forêt</strong> et facilite l'<strong>authentification multi-domaines</strong> (notamment via l'UPN). Port <code>3268</code>. Plusieurs DC peuvent l'héberger.", tags: ["système"] },
  { acronym: "Réplication", name: "Réplication Active Directory", category: "système", definition: "Synchronisation <strong>multi-maître</strong> des données entre contrôleurs de domaine : chaque DC peut écrire, et toute modification est propagée aux autres. Réplique l'annuaire (<code>NTDS.dit</code>) et le dossier <strong>SYSVOL</strong> (GPO, scripts). Assure la <strong>cohérence</strong> des données et la <strong>tolérance de panne</strong>.", tags: ["système"] },
  { acronym: "SID", name: "Security Identifier", category: "système", definition: "Identifiant de <strong>sécurité</strong> unique d'un objet AD (utilisateur, groupe, ordinateur). C'est lui qui est utilisé pour gérer les <strong>permissions NTFS et AD</strong>. Unique et <strong>immuable</strong> : il ne change pas même si l'objet est déplacé ou renommé.", tags: ["système", "sécurité"] },
  { acronym: "GUID", name: "Globally Unique Identifier (ObjectGUID)", category: "système", definition: "Identifiant <strong>technique</strong> d'un objet AD, codé sur <strong>128 bits</strong>, unique dans toute la forêt. Attribué à la création et <strong>immuable</strong> (ne change jamais, même en cas de déplacement ou de renommage). À distinguer du <strong>SID</strong>, qui sert lui à la sécurité et aux accès.", tags: ["système"] },
  { acronym: "UPN", name: "UserPrincipalName", category: "système", definition: "Identifiant de connexion <strong>moderne</strong> ressemblant à une adresse e-mail : <code>nom@domaine</code> (ex. <code>liam@adrar.local</code>). Unique dans toute la <strong>forêt</strong>, il est le <strong>format recommandé</strong> pour l'ouverture de session (plus clair, et compatible cloud/Microsoft 365). À comparer au <strong>sAMAccountName</strong> historique (<code>ADRAR\\liam</code>, ≤ 20 caractères, unique dans le domaine).", tags: ["système"] },
  { acronym: "DN", name: "Distinguished Name", category: "système", definition: "Chemin <strong>LDAP complet</strong> qui localise précisément un objet dans l'annuaire. Ex. <code>cn=Liam,ou=Salariés,dc=adrar,dc=local</code> : <strong>cn</strong> (Common Name) = nom de l'objet, <strong>ou</strong> = unité d'organisation, <strong>dc</strong> = composant du domaine.", tags: ["système"] },
  { acronym: "Registrar", name: "Bureau d'enregistrement de noms de domaine", category: "réseau", definition: "Entité accréditée (par l'<strong>ICANN</strong> à l'international, l'<strong>AFNIC</strong> pour le <code>.fr</code>) qui permet d'<strong>enregistrer et gérer des noms de domaine</strong>. On loue un domaine de <strong>1 à 10 ans</strong>, avec renouvellement obligatoire. Exemples : OVHcloud, Gandi, Namecheap.", tags: ["réseau"] },
  { acronym: "OS", name: "Operating System", category: "système", definition: "Système d'exploitation. Gère les ressources matérielles et fournit les services aux applications. Familles : <strong>Windows</strong> (NT kernel), <strong>Linux</strong> (kernel monolithique), <strong>macOS</strong> (XNU). En TSSR : Windows Server et Linux Server sont incontournables.", tags: ["système"] },
  { acronym: "CLI", name: "Command Line Interface", category: "système", definition: "Interface en ligne de commande. Plus puissante que l'interface graphique pour l'administration système. Windows : <code>cmd.exe</code> et <code>PowerShell</code>. Linux : <code>bash</code>, <code>zsh</code>. La maîtrise du CLI est fondamentale en TSSR.", tags: ["système"] },
  { acronym: "SSH", name: "Secure Shell", category: "système", definition: "Protocole d'accès distant sécurisé. Chiffre la connexion (remplace Telnet). Port <code>22</code>. Authentification par <strong>mot de passe</strong> ou <strong>clé publique/privée</strong> (recommandé). Permet aussi le transfert de fichiers (<strong>SCP</strong>, <strong>SFTP</strong>).", tags: ["système", "protocole", "sécurité"] },
  { acronym: "RDP", name: "Remote Desktop Protocol", category: "système", definition: "Protocole Microsoft d'accès bureau à distance. Port <code>3389</code>. Permet de prendre le contrôle graphique d'une machine Windows distante. Cible fréquente d'attaques → à protéger par VPN ou MFA.", tags: ["système", "protocole"] },
  { acronym: "WSUS", name: "Windows Server Update Services", category: "système", definition: "Service Microsoft de gestion centralisée des mises à jour Windows. Les machines du domaine récupèrent leurs MAJ depuis le serveur WSUS interne plutôt que depuis Microsoft. Permet de contrôler et tester les mises à jour avant déploiement.", tags: ["système"] },

  // PROTOCOLE
  { acronym: "HTTP", name: "HyperText Transfer Protocol", category: "protocole", definition: "Protocole de transfert de pages web. Port <code>80</code>. Non chiffré → remplacé par <strong>HTTPS</strong> (port <code>443</code>) qui ajoute TLS. Méthodes principales : <strong>GET</strong> (récupérer), <strong>POST</strong> (envoyer), <strong>PUT</strong> (modifier), <strong>DELETE</strong> (supprimer).", tags: ["protocole", "réseau"] },
  { acronym: "TLS", name: "Transport Layer Security", category: "protocole", definition: "Protocole de chiffrement des communications réseau. Successeur de <strong>SSL</strong> (obsolète). Utilisé par HTTPS, SMTPS, LDAPS. Fournit : <strong>confidentialité</strong> (chiffrement), <strong>intégrité</strong> (MAC), <strong>authentification</strong> (certificats). Version actuelle : TLS 1.3.", tags: ["protocole", "sécurité"] },
  { acronym: "SSL", name: "Secure Sockets Layer", category: "protocole", definition: "Ancêtre de TLS, aujourd'hui obsolète et vulnérable. Ne plus utiliser en production. Les termes 'certificat SSL' et 'SSL/TLS' sont encore utilisés dans le langage courant mais désignent en réalité <strong>TLS</strong>.", tags: ["protocole", "sécurité"] },
  { acronym: "FTP", name: "File Transfer Protocol", category: "protocole", definition: "Protocole de transfert de fichiers. Ports <code>20</code> (données) et <code>21</code> (contrôle). Non chiffré → utiliser <strong>SFTP</strong> (via SSH, port <code>22</code>) ou <strong>FTPS</strong> (FTP + TLS). FTP simple à éviter absolument en production.", tags: ["protocole"] },
  { acronym: "SMTP", name: "Simple Mail Transfer Protocol", category: "protocole", definition: "Protocole d'envoi d'emails. Port <code>25</code> (serveur à serveur), <code>587</code> (soumission avec auth), <code>465</code> (SMTPS chiffré). Pour la réception : <strong>IMAP</strong> (port <code>143</code>/<code>993</code>) ou <strong>POP3</strong> (port <code>110</code>/<code>995</code>).", tags: ["protocole"] },
  { acronym: "SNMP", name: "Simple Network Management Protocol", category: "protocole", definition: "Protocole de supervision réseau. Permet de collecter des informations sur les équipements (switches, routeurs, serveurs). Port <code>161</code> (UDP). Versions : SNMPv1 (obsolète), SNMPv2c, <strong>SNMPv3</strong> (chiffré, recommandé).", tags: ["protocole", "réseau"] },
  { acronym: "NTP", name: "Network Time Protocol", category: "protocole", definition: "Protocole de synchronisation de l'horloge. Port <code>123</code> (UDP). Crucial pour Active Directory (Kerberos tolère 5 minutes de décalage max). Hiérarchie de <strong>strates</strong> : Stratum 0 (horloge atomique) → Stratum 1 → Stratum 2...", tags: ["protocole"] },
  { acronym: "ICMP", name: "Internet Control Message Protocol", category: "protocole", definition: "Protocole de messages de contrôle IP. Utilisé par <code>ping</code> (echo request/reply) et <code>traceroute</code>. Pas de notion de port. Souvent filtré par les firewalls. Couche 3 du modèle OSI.", tags: ["protocole", "réseau"] },

  // VIRTUALISATION
  { acronym: "VM", name: "Virtual Machine", category: "virtualisation", definition: "Machine virtuelle : émulation complète d'un ordinateur physique. Dispose de son propre OS, CPU virtuel, RAM, disque. Isolée des autres VM. Gérée par un <strong>hyperviseur</strong>. Format de disque Hyper-V : <strong>VHDX</strong>. VMware : <strong>VMDK</strong>.", tags: ["virtualisation"] },
  { acronym: "Hyper-V", name: "Hyperviseur Microsoft", category: "virtualisation", definition: "Hyperviseur de type 1 intégré à Windows Server et Windows 10/11 Pro. Activable comme <strong>rôle Windows</strong>. Géré via Hyper-V Manager ou PowerShell. Switch virtuel : <strong>Externe</strong> (accès LAN réel), <strong>Interne</strong> (hôte+VM), <strong>Privé</strong> (VM entre elles uniquement).", tags: ["virtualisation", "système"] },
  { acronym: "ESXi", name: "VMware ESXi", category: "virtualisation", definition: "Hyperviseur de type 1 de VMware. S'installe directement sur le matériel (<em>bare metal</em>). Géré via <strong>vCenter Server</strong>. Fonctionnalités avancées : <strong>vMotion</strong> (migration à chaud), <strong>DRS</strong> (équilibrage), <strong>HA</strong> (haute disponibilité).", tags: ["virtualisation"] },
  { acronym: "KVM", name: "Kernel-based Virtual Machine", category: "virtualisation", definition: "Hyperviseur intégré au noyau Linux. Transforme Linux en hyperviseur de type 1. Base de <strong>Proxmox VE</strong>. Utilisé en combinaison avec <strong>QEMU</strong>. Très performant, open-source, populaire en entreprise.", tags: ["virtualisation"] },
  { acronym: "VHDX", name: "Virtual Hard Disk Extended", category: "virtualisation", definition: "Format de disque virtuel Microsoft (Hyper-V). Supporte jusqu'à <strong>64 To</strong>. Amélioration du format VHD. Supporte les snapshots, la résistance aux coupures de courant. Format recommandé pour les VM Hyper-V modernes.", tags: ["virtualisation", "stockage"] },
  { acronym: "OVF", name: "Open Virtualization Format", category: "virtualisation", definition: "Format standard d'empaquetage de VM. Permet d'exporter/importer des VM entre hyperviseurs différents. <strong>OVA</strong> = archive OVF (un seul fichier). Utile pour les déploiements de templates.", tags: ["virtualisation"] },

  // HARDWARE
  { acronym: "RJ45", name: "Registered Jack 45", category: "hardware", definition: "Connecteur standard pour câbles réseau Ethernet. 8 broches. Se clipse dans les ports des switches, routeurs, PC. Le câble qui va dedans est du <strong>Cat5e</strong>, <strong>Cat6</strong>, ou <strong>Cat6a</strong>. Ne pas confondre avec <strong>RJ11</strong> (téléphone, 4 broches).", tags: ["hardware", "réseau"] },
  { acronym: "RJ11", name: "Registered Jack 11", category: "hardware", definition: "Connecteur téléphonique, plus petit que le RJ45. 4 broches. Utilisé pour les lignes téléphoniques analogiques (ADSL, fax). Quasiment plus utilisé en infrastructure réseau moderne.", tags: ["hardware"] },
  { acronym: "CPU", name: "Central Processing Unit", category: "hardware", definition: "Processeur central d'un ordinateur. Exécute les instructions des programmes. Caractéristiques clés : <strong>nombre de cœurs</strong>, <strong>fréquence</strong> (GHz), <strong>cache L1/L2/L3</strong>, <strong>TDP</strong> (consommation thermique). Ex : Intel i7 Ultra 265K, AMD Ryzen 9.", tags: ["hardware"] },
  { acronym: "RAM", name: "Random Access Memory", category: "hardware", definition: "Mémoire vive. Stockage temporaire des données en cours d'utilisation. <strong>DDR4</strong> : standard actuel en entreprise. <strong>DDR5</strong> : nouvelle génération (plus rapide). Plus il y a de RAM, plus on peut faire tourner de VM ou de services simultanément.", tags: ["hardware"] },
  { acronym: "GPU", name: "Graphics Processing Unit", category: "hardware", definition: "Processeur graphique. Initialement pour l'affichage, aujourd'hui utilisé pour le <strong>calcul parallèle massif</strong> (IA, machine learning, rendu 3D). Ex : RTX 5070. En TSSR, rarement critique sauf pour les serveurs de rendu ou IA.", tags: ["hardware"] },
  { acronym: "SSD", name: "Solid State Drive", category: "hardware", definition: "Disque à mémoire flash, sans pièce mécanique. Beaucoup plus rapide qu'un HDD. Types : <strong>SATA</strong> (jusqu'à 550 Mo/s), <strong>NVMe</strong> (jusqu'à 7000 Mo/s via PCIe). Recommandé pour l'OS et les VM. Durée de vie mesurée en <strong>TBW</strong> (terabytes écrits).", tags: ["hardware", "stockage"] },
  { acronym: "HDD", name: "Hard Disk Drive", category: "hardware", definition: "Disque dur mécanique. Plateau magnétique en rotation + tête de lecture. Plus lent que le SSD mais moins cher au Go. Encore utilisé pour le <strong>stockage massif</strong> (NAS, archives). Sensible aux chocs. Vitesse : 5400 ou 7200 RPM.", tags: ["hardware", "stockage"] },
  { acronym: "NVMe", name: "Non-Volatile Memory Express", category: "hardware", definition: "Protocole de communication pour SSD ultra-rapides via le bus <strong>PCIe</strong>. Remplace l'ancien protocole AHCI/SATA. Latences très faibles. Format physique : <strong>M.2</strong> (petite carte) ou carte PCIe. Standard sur les machines modernes.", tags: ["hardware", "stockage"] },
  { acronym: "PSU", name: "Power Supply Unit", category: "hardware", definition: "Alimentation électrique d'un PC ou serveur. Convertit le courant secteur (230V AC) en tensions continues (12V, 5V, 3.3V). Certification <strong>80 Plus</strong> indique l'efficacité énergétique (Bronze, Silver, Gold, Platinum). En serveur : souvent redondante (2 alimentations).", tags: ["hardware"] },
  { acronym: "UPS", name: "Uninterruptible Power Supply", category: "hardware", definition: "Onduleur / alimentation sans interruption. Batterie de secours qui prend le relais en cas de coupure secteur. Permet un arrêt propre des serveurs. Indispensable en salle serveur. Durée d'autonomie : quelques minutes à plusieurs heures.", tags: ["hardware"] },
  { acronym: "NIC", name: "Network Interface Card", category: "hardware", definition: "Carte réseau. Composant physique permettant à un ordinateur de se connecter au réseau. Intégrée à la carte mère ou en carte d'extension PCIe. Identifiée par son adresse <strong>MAC</strong>. Vitesses : 100 Mbps, 1 Gbps, 10 Gbps.", tags: ["hardware", "réseau"] },
  { acronym: "Switch", name: "Commutateur réseau", category: "hardware", definition: "Équipement réseau de niveau 2 (Liaison). Relie plusieurs machines sur un même réseau local. Apprend les adresses MAC et envoie les trames uniquement au bon port (contrairement au hub qui diffuse partout). <strong>Switch manageable</strong> : configurable (VLANs, QoS, monitoring).", tags: ["hardware", "réseau"] },
  { acronym: "Routeur", name: "Router", category: "hardware", definition: "Équipement réseau de niveau 3 (Réseau). Interconnecte plusieurs réseaux et route les paquets IP. Maintient une <strong>table de routage</strong>. Votre box Internet est un routeur. En entreprise : Cisco, Juniper, pfSense (logiciel).", tags: ["hardware", "réseau"] },
  { acronym: "Firewall", name: "Pare-feu", category: "hardware", definition: "Équipement (matériel ou logiciel) filtrant le trafic réseau selon des règles. Peut être <strong>matériel</strong> (Fortinet, Palo Alto, pfSense) ou <strong>logiciel</strong> (Windows Defender Firewall, iptables). Niveau 3/4 (IP/ports) ou niveau 7 (applicatif = NGFW).", tags: ["hardware", "sécurité", "réseau"] },
  { acronym: "AP", name: "Access Point", category: "hardware", definition: "Point d'accès Wi-Fi. Connecte les appareils sans fil au réseau filaire. Se branche sur un switch via RJ45. Standards : <strong>802.11n</strong> (Wi-Fi 4), <strong>802.11ac</strong> (Wi-Fi 5), <strong>802.11ax</strong> (Wi-Fi 6). Géré seul ou via un <strong>contrôleur Wi-Fi</strong> centralisé.", tags: ["hardware", "réseau"] },
  { acronym: "Rack", name: "Baie de serveurs", category: "hardware", definition: "Armoire standardisée pour héberger les équipements réseau et serveurs. Unité de mesure : <strong>U</strong> (1U = 44,45 mm de hauteur). Un rack standard = 42U. Contient serveurs, switches, patch panels, onduleurs. Câblage structuré derrière.", tags: ["hardware"] },
  { acronym: "KVM (switch)", name: "Keyboard Video Mouse", category: "hardware", definition: "Switch permettant de contrôler plusieurs serveurs physiques avec un seul clavier/écran/souris. À ne pas confondre avec <strong>KVM (virtualisation)</strong> qui est Kernel-based Virtual Machine. Très utilisé dans les salles serveurs.", tags: ["hardware"] },
  { acronym: "PoE", name: "Power over Ethernet", category: "hardware", definition: "Technologie alimentant des équipements via le câble RJ45. Évite un câble d'alimentation séparé. Utilisé pour les <strong>points d'accès Wi-Fi</strong>, caméras IP, téléphones VoIP. Standards : <strong>802.3af</strong> (15W), <strong>802.3at</strong> (30W), <strong>802.3bt</strong> (90W).", tags: ["hardware", "réseau"] },
  { acronym: "BIOS/UEFI", name: "Basic Input Output System / Unified Extensible Firmware Interface", category: "hardware", definition: "<strong>BIOS</strong> : firmware historique de démarrage des PC. <strong>UEFI</strong> : remplaçant moderne du BIOS. Interface graphique, support des disques >2To, démarrage sécurisé (<strong>Secure Boot</strong>), démarrage plus rapide. Permet de configurer l'ordre de boot, les options matérielles.", tags: ["hardware"] },
  { acronym: "TPM", name: "Trusted Platform Module", category: "hardware", definition: "Puce de sécurité intégrée à la carte mère. Stocke les clés de chiffrement, certificats et hachages de façon sécurisée. Utilisé par <strong>BitLocker</strong> (chiffrement Windows), Secure Boot, et Windows 11 (requis). Version actuelle : <strong>TPM 2.0</strong>.", tags: ["hardware", "sécurité"] },
  { acronym: "Cat5e/Cat6/Cat6a", name: "Catégories de câbles Ethernet", category: "hardware", definition: "Standards de câbles RJ45. <strong>Cat5e</strong> : 1 Gbps jusqu'à 100m. <strong>Cat6</strong> : 10 Gbps jusqu'à 55m (1 Gbps à 100m). <strong>Cat6a</strong> : 10 Gbps jusqu'à 100m. <strong>Cat7/Cat8</strong> : 25-40 Gbps pour datacenters. Pour une infra moderne, Cat6 minimum.", tags: ["hardware", "réseau"] },
  { acronym: "SFP", name: "Small Form-factor Pluggable", category: "hardware", definition: "Module enfichable pour connexions fibre optique ou cuivre haute vitesse sur switches/routeurs. <strong>SFP</strong> : 1 Gbps. <strong>SFP+</strong> : 10 Gbps. <strong>QSFP</strong> : 40/100 Gbps. Permet de choisir le type de connectique selon les besoins.", tags: ["hardware", "réseau"] },

  // STOCKAGE
  { acronym: "RAID", name: "Redundant Array of Independent Disks", category: "stockage", definition: "Technique de regroupement de disques. <strong>RAID 0</strong> : agrégat (vitesse, 0 redondance). <strong>RAID 1</strong> : miroir (redondance totale). <strong>RAID 5</strong> : parité distribuée (équilibre). <strong>RAID 6</strong> : double parité. <strong>RAID 10</strong> : miroir + agrégat.", tags: ["stockage"] },
  { acronym: "NAS", name: "Network Attached Storage", category: "stockage", definition: "Serveur de stockage connecté au réseau. Accessible via <strong>SMB/CIFS</strong> (Windows) ou <strong>NFS</strong> (Linux). Idéal pour le partage de fichiers en entreprise. Solutions : Synology, QNAP, TrueNAS.", tags: ["stockage", "réseau"] },
  { acronym: "SAN", name: "Storage Area Network", category: "stockage", definition: "Réseau dédié au stockage. Le stockage apparaît comme un disque local pour les serveurs. Protocoles : <strong>iSCSI</strong> (sur TCP/IP), <strong>Fibre Channel</strong> (réseau dédié). Utilisé pour les environnements virtualisés haute performance.", tags: ["stockage", "réseau"] },
  { acronym: "iSCSI", name: "Internet Small Computer System Interface", category: "stockage", definition: "Protocole permettant d'utiliser le protocole SCSI sur un réseau TCP/IP. Permet de connecter un SAN via le réseau Ethernet existant. Moins cher que Fibre Channel. Utilisé pour le stockage partagé des VM.", tags: ["stockage", "protocole"] },
  { acronym: "SMB", name: "Server Message Block", category: "stockage", definition: "Protocole de partage de fichiers Windows. Port <code>445</code>. Versions : SMBv1 (vulnérable, désactiver !), <strong>SMBv2</strong>, <strong>SMBv3</strong> (chiffrement). Utilisé par les partages réseau Windows (<code>\\\\serveur\\partage</code>). Aussi appelé <strong>CIFS</strong>.", tags: ["stockage", "protocole"] },
  { acronym: "NFS", name: "Network File System", category: "stockage", definition: "Protocole de partage de fichiers Unix/Linux. Port <code>2049</code>. Permet de monter un répertoire distant comme s'il était local. Très utilisé en environnement Linux et pour le stockage partagé des VM sous VMware/KVM.", tags: ["stockage", "protocole"] },

  // EXPRESSIONS
  { acronym: "Specs", name: "Spécifications techniques", category: "expression", definition: "Caractéristiques techniques d'un équipement. Les specs d'un serveur incluent : CPU (modèle, cœurs, fréquence), RAM (quantité, type DDR), stockage (type SSD/HDD, capacité), réseau (NIC, vitesse), OS. Toujours vérifier les specs avant d'installer un rôle serveur.", tags: ["expression", "hardware"] },
  { acronym: "Local", name: "En local / localement", category: "expression", definition: "Se dit d'une ressource accessible uniquement sur la machine elle-même ou sur le réseau local (<strong>LAN</strong>). Opposé à <strong>distant</strong> ou <strong>remote</strong>. Ex : 'la base de données tourne en local' = sur le même serveur. 'Accès local uniquement' = pas accessible depuis Internet.", tags: ["expression", "réseau"] },
  { acronym: "Remote / Distant", name: "Accès à distance", category: "expression", definition: "Accès à une ressource ou machine depuis un autre endroit (réseau différent, Internet). Outils : <strong>SSH</strong> (Linux), <strong>RDP</strong> (Windows), <strong>VNC</strong>, <strong>TeamViewer</strong>, <strong>RustDesk</strong>. Sécuriser toujours l'accès distant par VPN ou MFA.", tags: ["expression", "réseau"] },
  { acronym: "On-premise / On-prem", name: "Hébergement sur site", category: "expression", definition: "Infrastructure hébergée physiquement dans les locaux de l'entreprise. S'oppose au <strong>Cloud</strong>. Avantages : contrôle total, données sur site. Inconvénients : coût matériel, maintenance. La plupart des entreprises utilisent aujourd'hui un <strong>modèle hybride</strong> (on-prem + cloud).", tags: ["expression"] },
  { acronym: "Cloud", name: "Informatique en nuage", category: "expression", definition: "Hébergement et services fournis via Internet par un tiers. Modèles : <strong>IaaS</strong> (Infrastructure), <strong>PaaS</strong> (Plateforme), <strong>SaaS</strong> (Logiciel). Fournisseurs : AWS, Azure, Google Cloud. <strong>Cloud privé</strong> = infra cloud interne à l'entreprise.", tags: ["expression"] },
  { acronym: "Bande passante", name: "Bandwidth", category: "expression", definition: "Débit maximal d'une connexion réseau. Mesurée en <strong>Mbps</strong> ou <strong>Gbps</strong>. À distinguer de la <strong>latence</strong> (délai). Une fibre 1 Gbps peut avoir une latence élevée si le réseau est saturé. En entreprise : prévoir de la marge (ne jamais saturer à 100%).", tags: ["expression", "réseau"] },
  { acronym: "Latence", name: "Latency / Ping", category: "expression", definition: "Délai de transmission d'un paquet d'un point A à un point B. Mesurée en <strong>ms</strong> (millisecondes). Testée avec <code>ping</code>. Critique pour la VoIP, jeux en ligne, visioconférence. Différente du débit : on peut avoir un débit élevé avec une latence élevée.", tags: ["expression", "réseau"] },
  { acronym: "Firmware", name: "Micrologiciel", category: "expression", definition: "Logiciel embarqué dans un équipement matériel (switch, routeur, imprimante, UEFI). Pilote le fonctionnement de l'équipement à bas niveau. À mettre à jour régulièrement pour corriger les <strong>vulnérabilités</strong>. Distinct du driver (pilote OS).", tags: ["expression", "hardware"] },
  { acronym: "Driver / Pilote", name: "Device Driver", category: "expression", definition: "Logiciel permettant à l'OS de communiquer avec un composant matériel (carte graphique, carte réseau, imprimante). Sans driver, l'équipement ne fonctionne pas. Windows Update installe souvent les drivers automatiquement. Problème courant en TSSR : driver manquant ou obsolète.", tags: ["expression", "hardware", "système"] },
  { acronym: "Patch", name: "Correctif logiciel", category: "expression", definition: "Mise à jour ciblée corrigeant un bug ou une vulnérabilité de sécurité. <strong>Patch de sécurité</strong> = critique, à appliquer rapidement. <strong>Patch Tuesday</strong> = mises à jour Microsoft publiées chaque 2e mardi du mois. Géré en entreprise via <strong>WSUS</strong> ou SCCM.", tags: ["expression", "sécurité"] },
  { acronym: "Uptime", name: "Taux de disponibilité", category: "expression", definition: "Temps de fonctionnement continu d'un système. Exprimé en pourcentage : <strong>99,9%</strong> = 8,7h d'arrêt/an. <strong>99,99%</strong> (4 neuf) = 52 min/an. <strong>99,999%</strong> (5 neuf) = 5 min/an. Objectif de haute disponibilité. S'oppose au <strong>downtime</strong> (temps d'arrêt).", tags: ["expression"] },
  { acronym: "Failover", name: "Basculement automatique", category: "expression", definition: "Mécanisme de bascule automatique vers un système de secours en cas de panne. Ex : si le serveur principal tombe, le serveur secondaire prend le relais automatiquement. Base de la <strong>haute disponibilité (HA)</strong>. Utilisé pour les DC, serveurs web, liens réseau.", tags: ["expression", "sécurité"] },
  { acronym: "Bare metal", name: "Matériel nu", category: "expression", definition: "Installation directement sur le matériel physique, sans OS intermédiaire. Un hyperviseur <strong>bare metal</strong> (type 1) s'installe directement sur le serveur. Opposé au <strong>type 2</strong> qui s'installe sur un OS hôte. Plus performant car pas de couche OS supplémentaire.", tags: ["expression", "virtualisation"] },
  { acronym: "Scalabilité", name: "Scalability", category: "expression", definition: "Capacité d'un système à monter en charge. <strong>Scale up</strong> (vertical) : ajouter plus de CPU/RAM au même serveur. <strong>Scale out</strong> (horizontal) : ajouter plus de serveurs. Le scale out est préféré en cloud et architecture moderne car plus flexible.", tags: ["expression"] },
  { acronym: "Redondance", name: "Redundancy", category: "expression", definition: "Duplication de composants critiques pour éviter un point de défaillance unique (<strong>SPOF</strong>). Exemples : 2 alimentations, 2 liens réseau, 2 contrôleurs de domaine, RAID. Principe fondamental en infrastructure : tout composant critique doit être redondant.", tags: ["expression", "sécurité"] },
  { acronym: "SPOF", name: "Single Point of Failure", category: "expression", definition: "Point de défaillance unique : composant dont la panne entraîne l'arrêt complet du service. À identifier et éliminer dans toute architecture critique. Solution : redondance. Ex : un seul DC = SPOF. Un seul lien Internet = SPOF.", tags: ["expression", "sécurité"] },
  { acronym: "Ticketing", name: "Système de gestion de tickets", category: "expression", definition: "Outil de suivi des demandes et incidents. Chaque demande = un ticket avec statut (ouvert, en cours, résolu). Outils : <strong>GLPI</strong>, ServiceNow, Jira Service Management. Fondamental en helpdesk TSSR. Permet de tracer, prioriser et mesurer les interventions.", tags: ["expression", "système"] },
  { acronym: "Helpdesk / Support N1/N2/N3", name: "Niveaux de support technique", category: "expression", definition: "<strong>N1</strong> : premier contact, questions basiques, redémarrages, réinitialisation MDP. <strong>N2</strong> : technicien, configuration, diagnostic approfondi. <strong>N3</strong> : expert, problèmes complexes, escalade éditeur. En TSSR, on intervient surtout en <strong>N1 et N2</strong>.", tags: ["expression", "système"] },
  { acronym: "SLA", name: "Service Level Agreement", category: "expression", definition: "Accord de niveau de service. Contrat définissant les engagements de qualité : temps de réponse, disponibilité, délai de résolution. Ex : SLA critique = résolution en moins de 4h. Base contractuelle des relations client/prestataire IT.", tags: ["expression"] },
  { acronym: "ToIP / VoIP", name: "Téléphonie sur IP / Voice over IP", category: "expression", definition: "Transmission de la voix via le réseau IP. Remplace la téléphonie analogique. Protocoles : <strong>SIP</strong>, <strong>H.323</strong>. Sensible à la latence et à la gigue (<strong>jitter</strong>). Nécessite une bonne <strong>QoS</strong> sur le réseau. Solutions : Asterisk, 3CX, Teams Phone.", tags: ["expression", "réseau"] },
  { acronym: "Supervision / Monitoring", name: "Surveillance de l'infrastructure", category: "expression", definition: "Surveillance en temps réel de l'état des équipements et services. Métriques : CPU, RAM, disque, bande passante, temps de réponse. Outils : <strong>Centreon</strong>, Zabbix, Nagios, Prometheus+Grafana. Alerte les admins en cas d'anomalie.", tags: ["expression", "réseau"] },

  // SYSTÈME / AD (complément)
  { acronym: "NTFS", name: "New Technology File System", category: "système", definition: "Système de fichiers de Windows. Gère les <strong>droits d'accès</strong> (sécurité NTFS), les gros fichiers, le chiffrement (<strong>EFS</strong>), la compression et la journalisation. C'est le NTFS qui fait le <strong>vrai contrôle d'accès</strong> aux dossiers (le partage ne fait qu'ouvrir la porte réseau).", tags: ["système", "stockage"] },
  { acronym: "IIS", name: "Internet Information Services", category: "système", definition: "Serveur <strong>web</strong> de Windows Server (rôle). Héberge des sites et applications ; chaque site est identifié par une <strong>liaison</strong> (nom d'hôte + port + IP). Utilise des <strong>pools d'applications</strong> et le compte <code>IIS_IUSRS</code> pour l'accès NTFS.", tags: ["système"] },
  { acronym: "AGDLP", name: "Account → Global → Domain Local → Permission", category: "système", definition: "Stratégie Microsoft d'attribution des droits : placer les <strong>comptes</strong> dans un groupe <strong>Global</strong> (par métier), ce Global dans un groupe <strong>Domaine Local</strong> (par ressource + droit), et la <strong>permission</strong> NTFS sur le Domaine Local. Évite d'attribuer des droits directement aux utilisateurs.", tags: ["système", "sécurité"] },
  { acronym: "RID", name: "Relative Identifier", category: "système", definition: "Partie <strong>relative</strong> (variable) d'un <strong>SID</strong>, unique par objet dans le domaine. Le rôle FSMO <strong>Maître RID</strong> distribue des blocs de RID aux contrôleurs de domaine pour garantir l'unicité.", tags: ["système"] },
  { acronym: "PDC", name: "Primary Domain Controller (Emulator)", category: "système", definition: "Rôle FSMO de <strong>domaine</strong> servant de référence pour l'<strong>authentification</strong>, les changements de <strong>mot de passe</strong>, les verrouillages de compte et la <strong>synchronisation horaire</strong> (référence de temps du domaine).", tags: ["système"] },
  { acronym: "NTDS", name: "NT Directory Services", category: "système", definition: "Base de données de l'annuaire Active Directory, stockée dans le fichier <code>NTDS.dit</code> sur chaque contrôleur de domaine. Répliquée entre les DC.", tags: ["système"] },
  { acronym: "SAM", name: "Security Account Manager", category: "système", definition: "Base des <strong>comptes locaux</strong> d'une machine Windows (utilisateurs et groupes locaux), utilisée hors domaine (workgroup). À distinguer de l'annuaire <strong>Active Directory</strong> (comptes de domaine).", tags: ["système", "sécurité"] },
  { acronym: "RDS", name: "Remote Desktop Services", category: "système", definition: "Rôle Windows Server de <strong>services Bureau à distance</strong> : permet à plusieurs utilisateurs d'ouvrir des sessions distantes sur un serveur (au-delà du simple RDP d'administration).", tags: ["système"] },
  { acronym: "UO", name: "Unité d'Organisation", category: "système", definition: "Terme français pour <strong>OU</strong> (<em>Organizational Unit</em>) : conteneur d'Active Directory servant à organiser les objets (utilisateurs, ordinateurs, groupes) et à y appliquer des <strong>GPO</strong> ou une <strong>délégation</strong>.", tags: ["système"] },

  // RÉSEAU / WEB (complément)
  { acronym: "FQDN", name: "Fully Qualified Domain Name", category: "réseau", definition: "Nom <strong>complet</strong> d'une machine sur Internet : hôte + domaine + extension + racine. Ex. <code>www.example.com.</code> On le lit de droite (racine) à gauche (hôte). Sans ambiguïté, contrairement au nom court.", tags: ["réseau"] },
  { acronym: "TLD", name: "Top-Level Domain", category: "réseau", definition: "Extension (domaine de premier niveau) d'un nom de domaine : <code>.com</code>, <code>.fr</code>, <code>.org</code>… Gérés au sommet du DNS par les <strong>serveurs racine</strong>. Les <strong>TLD nationaux</strong> (<code>.fr</code>) sont administrés par un registre (AFNIC pour le .fr).", tags: ["réseau"] },
  { acronym: "VPS", name: "Virtual Private Server", category: "virtualisation", definition: "Serveur <strong>virtuel privé</strong> : une machine virtuelle dédiée avec des ressources garanties, louée chez un hébergeur. Bon compromis coût / contrôle entre l'hébergement <strong>mutualisé</strong> et le serveur <strong>dédié</strong>.", tags: ["virtualisation", "réseau"] },
  { acronym: "ICANN", name: "Internet Corporation for Assigned Names and Numbers", category: "réseau", definition: "Organisme mondial coordonnant les <strong>noms de domaine</strong> et les adresses IP. Il <strong>accrédite les registrars</strong> et supervise le système des TLD.", tags: ["réseau"] },
  { acronym: "AFNIC", name: "Association Française pour le Nommage Internet en Coopération", category: "réseau", definition: "Registre du domaine <strong><code>.fr</code></strong> (et autres extensions françaises). Encadre l'enregistrement des noms de domaine en <code>.fr</code> via les registrars.", tags: ["réseau"] },
  { acronym: "APIPA", name: "Automatic Private IP Addressing", category: "réseau", definition: "Adresse auto-attribuée en <code>169.254.x.x</code> quand un client ne trouve <strong>aucun serveur DHCP</strong>. Symptôme classique : la carte n'a <strong>pas reçu de configuration valide</strong> → pas de connectivité.", tags: ["réseau"] },
  { acronym: "MCLT", name: "Maximum Client Lead Time", category: "réseau", definition: "Paramètre du <strong>basculement DHCP</strong> (failover) : durée maximale pendant laquelle un serveur peut <strong>prolonger seul</strong> un bail si son partenaire est injoignable (défaut 1 h).", tags: ["réseau"] },
  { acronym: "HTTPS", name: "HyperText Transfer Protocol Secure", category: "protocole", definition: "Version <strong>chiffrée</strong> de HTTP : HTTP + <strong>TLS</strong>. Port <code>443</code>. Garantit confidentialité et intégrité, et authentifie le serveur via un <strong>certificat</strong>.", tags: ["protocole", "sécurité"] },
  { acronym: "SFTP", name: "SSH File Transfer Protocol", category: "protocole", definition: "Transfert de fichiers <strong>chiffré</strong> via <strong>SSH</strong> (port <code>22</code>). À ne pas confondre avec FTPS (FTP + TLS). Remplace avantageusement le FTP en clair.", tags: ["protocole", "sécurité"] },
  { acronym: "FTPS", name: "FTP Secure", category: "protocole", definition: "FTP sécurisé par <strong>TLS</strong>. Différent de <strong>SFTP</strong> (qui passe par SSH). Chiffre le canal de contrôle et/ou de données du FTP.", tags: ["protocole", "sécurité"] },
  { acronym: "WWW", name: "World Wide Web", category: "réseau", definition: "Le <strong>web</strong> : ensemble des pages liées entre elles et consultées via HTTP/HTTPS. Souvent utilisé comme sous-domaine (<code>www</code>) pointant vers le serveur web d'un site.", tags: ["réseau"] },
  { acronym: "CNAME", name: "Canonical Name", category: "protocole", definition: "Enregistrement DNS d'<strong>alias</strong> : fait pointer un nom vers un autre nom (ex. <code>www</code> → <code>serveur.domaine.local</code>).", tags: ["protocole", "réseau"] },
  { acronym: "SOA", name: "Start Of Authority", category: "protocole", definition: "Enregistrement DNS des <strong>informations de la zone</strong> : serveur DNS primaire, e-mail de l'administrateur, numéro de série (versionnage), délais de rafraîchissement.", tags: ["protocole", "réseau"] },
  { acronym: "PTR", name: "Pointer Record", category: "protocole", definition: "Enregistrement DNS <strong>inverse</strong> : traduit une <strong>adresse IP en nom</strong> (résolution inversée). Stocké dans une zone de recherche inversée.", tags: ["protocole", "réseau"] },
  { acronym: "SRV", name: "Service Record", category: "protocole", definition: "Enregistrement DNS qui <strong>localise un service</strong> (hôte + port). <strong>Vital pour Active Directory</strong> : les clients y trouvent les DC, le LDAP et le Kerberos du domaine.", tags: ["protocole", "réseau"] },
  { acronym: "MX", name: "Mail eXchanger", category: "protocole", definition: "Enregistrement DNS désignant le <strong>serveur de messagerie</strong> d'un domaine (où livrer les e-mails).", tags: ["protocole", "réseau"] },
  { acronym: "NS", name: "Name Server", category: "protocole", definition: "Enregistrement DNS désignant un <strong>serveur DNS faisant autorité</strong> sur la zone.", tags: ["protocole", "réseau"] },

  // STOCKAGE (complément)
  { acronym: "MBR", name: "Master Boot Record", category: "stockage", definition: "Ancien schéma de <strong>partitionnement</strong> : limité à <strong>2 To</strong> et <strong>4 partitions principales</strong>. Associé au démarrage <strong>BIOS</strong> (legacy). Encore utilisé pour la compatibilité.", tags: ["stockage"] },
  { acronym: "GPT", name: "GUID Partition Table", category: "stockage", definition: "Schéma de <strong>partitionnement moderne</strong> : supporte les disques <strong>&gt; 2 To</strong> et un grand nombre de partitions. Associé au démarrage <strong>UEFI</strong>. À privilégier aujourd'hui.", tags: ["stockage"] },
  { acronym: "FAT32", name: "File Allocation Table 32", category: "stockage", definition: "Système de fichiers <strong>très compatible</strong> (clés USB, anciens systèmes) mais limité : fichiers de <strong>4 Go max</strong>, peu de gestion de sécurité.", tags: ["stockage"] },
  { acronym: "exFAT", name: "Extended File Allocation Table", category: "stockage", definition: "Système de fichiers optimisé pour les <strong>supports amovibles</strong> (clés USB, disques externes). Pas de limite de taille de fichier notable, mais peu de gestion des droits.", tags: ["stockage"] },
];

